import{j as i,b as a,c as s,aa as l}from"./chunks/framework.Bxf40uRC.js";const m=JSON.parse('{"title":"Linux面试问题","description":"","frontmatter":{},"headers":[],"relativePath":"Linux/面试问题.md","filePath":"Linux/面试问题.md","lastUpdated":null}'),e={name:"Linux/面试问题.md"},t=l(`<h1 id="linux面试问题" tabindex="-1">Linux面试问题 <a class="header-anchor" href="#linux面试问题" aria-label="Permalink to &quot;Linux面试问题&quot;">​</a></h1><h2 id="linux系统中-你装了很多软件-这些服务运行起来之后-那每个软件它主要的进程状态-以及它每个软件主要进程占用的资源-究竟用什么方法可以查询到" tabindex="-1">linux系统中，你装了很多软件，这些服务运行起来之后，那每个软件它主要的进程状态，以及它每个软件主要进程占用的资源，究竟用什么方法可以查询到？ <a class="header-anchor" href="#linux系统中-你装了很多软件-这些服务运行起来之后-那每个软件它主要的进程状态-以及它每个软件主要进程占用的资源-究竟用什么方法可以查询到" aria-label="Permalink to &quot;linux系统中，你装了很多软件，这些服务运行起来之后，那每个软件它主要的进程状态，以及它每个软件主要进程占用的资源，究竟用什么方法可以查询到？&quot;">​</a></h2><p>ps aux ，a代表显示所有终端的进程，u代表用户友好格式，x表示显示没有终端控制的进程</p><h2 id="软链接和硬链接的区别" tabindex="-1">软链接和硬链接的区别？ <a class="header-anchor" href="#软链接和硬链接的区别" aria-label="Permalink to &quot;软链接和硬链接的区别？&quot;">​</a></h2><ol><li><p>软链接源文件和链接文件拥有不同的inode号，表明他们是两个不同的文件；</p></li><li><p>硬链接连源文件和链接文件共用一个inode号，就像一个文件存在多个文件名，但是是一个文件；</p></li><li><p>软链接明确写出了是链接文件，但是硬链接没有写出来，本质和链接完全平等的关系；</p></li><li><p>软链接支持跨文件系统建立，硬链接不支持；</p></li><li><p>原目标删除，软连接无法访问，但是硬链接可以，只有所有硬链接都删除，目标数据块数据才被释放；</p></li></ol><h2 id="什么是inode" tabindex="-1">什么是inode？ <a class="header-anchor" href="#什么是inode" aria-label="Permalink to &quot;什么是inode？&quot;">​</a></h2><p>表示文件或者目录在文件系统下的元数据信息，主要包括：</p><ol><li>文件类型和权限</li><li>文件的所有者和所属组</li><li>文件的大小</li><li>文件的创建时间、修改时间和访问时间</li><li>文件的链接数目</li><li>文件数据的物理位置（对于小文件直接包含数据，对于大文件保存了指向数据块的指针）</li></ol><h2 id="namespace-和-cgroup的区别" tabindex="-1">namespace 和 cgroup的区别？ <a class="header-anchor" href="#namespace-和-cgroup的区别" aria-label="Permalink to &quot;namespace 和 cgroup的区别？&quot;">​</a></h2><ul><li>namespace是linux内核提供的一种机制，用于隔离系统资源的视图，使得每个命令空间只能看到自己的资源，不知道其他命名空间中的存在； <ul><li>Docker通过namespace实现不同容器之间的资源隔离；</li><li>PID命名空间；</li><li>NetWork命名空间；</li><li>User命名空间；</li></ul></li><li>Cgroup：是linux提供的另一组机制，用于限制，统计和控制进程组的资源使用(如CPU、内存、磁盘I/O等)；</li></ul><h2 id="cron" tabindex="-1">cron <a class="header-anchor" href="#cron" aria-label="Permalink to &quot;cron&quot;">​</a></h2><ol><li><p>编辑crontab文件：使用crontab -e命令编辑当前用户的cron任务列表。如果需要编辑其他用户的cron人物列表，可以使用&quot;sudo crontab -u usuername -e&quot;</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /path/to/command arg1 arg2</span></span></code></pre></div><ul><li>第一列表示分钟</li><li>第二列表示小时</li><li>第三列表示天</li><li>第四列表示月份</li><li>第五列表示星期几</li><li>后续列：要执行的命令及参数</li></ul></li><li><p>常用时间设置：</p><ul><li><code>*</code> 表示所有可能的值，例如 <code>*</code> 表示每分钟/小时/日期/月份/星期。</li><li><code>*/n</code> 表示每隔 n 单位执行一次，例如 <code>*/5</code> 表示每隔 5 分钟执行一次。</li><li>使用逗号 <code>,</code> 分隔多个值，例如 <code>1,3,5</code> 表示 1、3、5 时执行。</li><li>使用范围 <code>-</code> 表示一个范围，例如 <code>1-5</code> 表示 1 到 5。</li><li>还可以结合上述用法，例如 <code>0 */2 * * *</code> 表示每隔 2 小时执行一次。、</li></ul></li></ol><h2 id="文件的三种时间-mtime-atime-ctime-分别在什么时候会发生改变-解释一下mtime-atime-ctime分别是什么" tabindex="-1">文件的三种时间(mtime, atime, ctime)，分别在什么时候会发生改变?解释一下mtime，atime，ctime分别是什么? <a class="header-anchor" href="#文件的三种时间-mtime-atime-ctime-分别在什么时候会发生改变-解释一下mtime-atime-ctime分别是什么" aria-label="Permalink to &quot;文件的三种时间(mtime, atime, ctime)，分别在什么时候会发生改变?解释一下mtime，atime，ctime分别是什么?&quot;">​</a></h2><ul><li><strong>mtime</strong>（修改时间）：文件内容最后一次被修改的时间。当你用编辑器修改文件内容并保存时，修改时间会被更新。</li><li><strong>atime</strong>（访问时间）：文件最后一次被访问的时间。当文件被读取、执行或访问时，访问时间会被更新。但需要注意的是，现代文件系统通常会将 atime 的更新延迟到一定程度，以提高性能，因此这个时间不一定总是准确的。</li><li><strong>ctime</strong>（状态改变时间）：文件的状态最后一次发生改变的时间。这个状态包括文件的权限和所有权的改变，以及文件内容的改变。除非文件内容发生了改变，否则 ctime 并不会更新。所以，当你修改文件权限、更改所有者或者修改文件元数据时，ctime 会被更新。</li></ul><h2 id="如何杀死一个进程" tabindex="-1">如何杀死一个进程？ <a class="header-anchor" href="#如何杀死一个进程" aria-label="Permalink to &quot;如何杀死一个进程？&quot;">​</a></h2><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1.</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ps</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -aux</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> redis</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> awk</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;NR == 1{print $2}&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> xargs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kill</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 2. </span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pkill</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 3. </span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pgrep</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> kill</span></span></code></pre></div>`,16),n=[t];function h(p,o,r,c,d,k){return a(),s("div",null,n)}const g=i(e,[["render",h]]);export{m as __pageData,g as default};
